import socket
import json
import threading

class GameServerUDP:
    def __init__(self, host='0.0.0.0', port=12345):
        self.server_address = (host, port)
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.bind(self.server_address)
        self.players = ['Player1', 'Player2', 'Player3']
        self.game_state = 'Running'
        self.run_server = True

    def process_request(self, data, client_address):
        try:
            decoded_data = data.decode('utf-8').strip()
            if decoded_data == 'status':
                response = {
                    'players': self.players,
                    'game_state': self.game_state
                }
                response_data = json.dumps(response).encode('utf-8')
                for i in range(0, len(response_data), 512):
                    self.sock.sendto(response_data[i:i+512], client_address)
        except Exception as e:
            print(f"Failed to process request: {e}")

    def start(self):
        print('Game Server listening on {}:{}'.format(*self.server_address))
        while self.run_server:
            try:
                data, client_address = self.sock.recvfrom(1024)
                threading.Thread(target=self.process_request, args=(data, client_address)).start()
            except KeyboardInterrupt:
                self.run_server = False

if __name__ == '__main__':
    server = GameServerUDP()
    server.start()